import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"16A. Internal Locum Conversion","description":"","frontmatter":{"title":"16A. Internal Locum Conversion","eba":"Medical Specialists 2022-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/employment/16A-internal-locum-conversion.md","filePath":"ebas/medical-specialists/employment/16A-internal-locum-conversion.md"}'),n={name:"ebas/medical-specialists/employment/16A-internal-locum-conversion.md"};function i(a,e,h,c,p,l){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_16a-internal-locum-conversion" tabindex="-1">16A. Internal Locum Conversion <a class="header-anchor" href="#_16a-internal-locum-conversion" aria-label="Permalink to &quot;16A. Internal Locum Conversion&quot;">​</a></h1><p>For the purpose of this clause only, any reference to Doctor means a Doctor employed pursuant to subclause 16.4 as an Internal Locum]</p><p><strong>16A.1</strong> Health Service offers</p><p><strong>(a)</strong> Subject to subclause 16A.2 and by 27 September 2021 in accordance with the NES, a Health Service must make an offer to a Doctor under this section if:</p><p><strong>(i)</strong> the Doctor has worked shifts for the Health Service for a period of 12 months beginning the day the employment started; and</p><p><strong>(ii)</strong> during at least the last 6 months of that period, the Doctor has worked a regular pattern of hours on an ongoing basis which, without significant adjustment, the Doctor could continue to work as a Full-Time Doctor or a Fractional Doctor (as the case may be).</p><p><strong>(b)</strong> The Health Service’s offer under subclause 16A.1 must:</p><p><strong>(i)</strong> be in writing; and</p><p><strong>(ii)</strong> be an offer for the Doctor to convert:</p><p>A. for a Doctor that has worked the equivalent of full-time hours during the period referred to in subclause 16A.1(a)(ii) – to full-time employment; or</p><p>B. for a Doctor that has worked less than the equivalent of full-time hours during the period referred to in subclause 16A.1 – to fractional employment that is</p><p>consistent with the regular pattern of hours worked during that period;</p><p><strong>(iii)</strong> be given to the Doctor within 21 days after the end of the 12- month period referred to in subclause 16A.1(a)(i).</p><p><strong>16A.2</strong> When Health Service offers not required</p><p><strong>(a)</strong> A Health Service is not required to make an offer under subclause 16A.1(a) to a Doctor if:</p><p><strong>(i)</strong> there are reasonable grounds not to make that offer; and</p><p><strong>(ii)</strong> the reasonable grounds are based on facts that are known, or reasonably foreseeable, at the time of deciding not to make the offer;</p><p><strong>(b)</strong> The Health Service must give written notice to a Doctor in accordance with subclause 16A.2 (d) if:</p><p><strong>(i)</strong> the Health Service decides under subclause 16A.2 16A.2 (a) not to make an offer to the Doctor; or</p><p><strong>(ii)</strong> the Doctor has been employed by the Health Service for the 12- month period referred to in subclause 16A.1(a)(i) but does not meet the requirement referred to in paragraph 16A.1(a)(ii).</p><p><strong>(c)</strong> Without limiting subclause 16A.2 , reasonable grounds for deciding not to make an offer include the following:</p><p><strong>(i)</strong> the Doctor’s position will cease to exist in the period of 12 months after the time of deciding not to make the offer, such as where a Doctor works shifts replacing a Doctors absence;</p><p><strong>(ii)</strong> the hours of work which the Doctor is required to perform will be significantly reduced in that period;</p><p><strong>(iii)</strong> there will be a significant change in either or both of the following in that period:</p><p>A. the days on which the Doctor’s hours of work are required to be performed;</p><p>B. the times at which the Doctor’s hours of work are required to be performed;</p><p>which cannot be accommodated within the days or times the Doctor is available to work during that period;</p><p><strong>(iv)</strong> making the offer would not comply with a recruitment or selection process required by or under a law of the Commonwealth or a State or a Territory.</p><p><strong>(d)</strong> The notice must:</p><p><strong>(i)</strong> advise the Doctor that the Health Service is not making an offer under subclause 16A.1; and</p><p><strong>(ii)</strong> include the details of the reasons for not making the offer (including any grounds on which the Health Service has decided to not make the offer); and</p><p><strong>(iii)</strong> be given to the Doctor within 21 days after the end of the 12- month period referred to in subclause 16A.1(a)(i).</p><p><strong>16A.3</strong> Doctor response</p><p><strong>(a)</strong> The Doctor must give the Health Service a written response to the offer made under 16A.1(a) within 21 days after the offer is given to the Doctor, stating whether the Doctor accepts or declines the offer.</p><p><strong>(b)</strong> If the Doctor fails to give the Health Service a written response in accordance with subclause 16A.3(a), the Doctor is taken to have declined the offer.</p><p><strong>16A.4</strong> Acceptances of offers</p><p><strong>(a)</strong> If the Doctor accepts the offer, the Health Service must, within 21 days after the day the acceptance is given to the Health Service, give written notice to the Doctor of the following:</p><p><strong>(i)</strong> whether the Doctor is converting to full-time employment or fractional employment;</p><p><strong>(ii)</strong> the Doctor’s hours of work after the conversion takes effect;</p><p><strong>(iii)</strong> the day the Doctor’s conversion to full-time or fractional employment takes effect</p><p><strong>(b)</strong> However, the Health Service must discuss with the Doctor the matters the Health Service intends to specify for the purposes of subclause 16A.4(a)(i)-</p><p><strong>(iii)</strong> before giving the notice.</p><p><strong>(c)</strong> The day specified for the purposes of subclause 16A.4(a)(iii) must be the first day of the Doctor’s first full pay period that starts after the day the notice is given, unless the Doctor and the Health Service agree to another day.</p><p><strong>16A.5</strong> Doctor requests</p><p><strong>(a)</strong> A Doctor may make a request of a Health Service under this clause if:</p><p><strong>(i)</strong> the Doctor has been employed by the Health Service for a period of at least 6 months beginning the day the employment started;</p><p><strong>(ii)</strong> the Doctor has, in the period of 6 months ending the day the request is given, worked a regular pattern of hours on an ongoing basis which, without significant adjustment, the Doctor could continue to work as a Full-Time Doctor or Fractional Doctor (as the case may be); and</p><p><strong>(iii)</strong> all of the following apply:</p><p>A. the Doctor has not, at any time during the period referred to in subclause 16A.5 (a)(ii), refused an offer made to the casual Doctor under subclause 16A.1;</p><p>B. the Health Service has not, at any time during that period, given the casual Doctor a notice in accordance with subclause 16A.2 (c)(i);</p><p>C. the Health Service has not, at any time during that period, given a response to the Doctor under subclause</p><p><strong>16A.6</strong> refusing a previous request made under this clause;</p><p>D. the request is not made during the period of 21 days after the period referred to in subclause 16A.1(a)(i).</p><p><strong>(b)</strong> The request must:</p><p><strong>(i)</strong> be in writing;</p><p><strong>(ii)</strong> be a request for the Doctor to convert:</p><p>A. for a Doctor that has worked the equivalent of full-time hours or shifts on a regular and systematic basis during the period referred to in subclause 16A.5 (a)(ii) – to full- time employment; or</p><p>B. for a Doctor that has worked less than the equivalent of full-time hours or shifts on a regular and systematic basis during the period referred to in subclause 16A.5 (a)(ii) – to fractional employment that is consistent with the regular pattern of hours or shifts worked during that period; and</p><p><strong>(iii)</strong> be given to the Health Service.</p><p><strong>16A.6</strong> Health Service must give a response</p><p>The Health Service must give the Doctor a written response to the request made under subclause 16.5 within 21 days after the request is given to the Health Service, stating whether the Health Service grants or refuses the request.</p><p><strong>16A.7</strong> Refusals of requests</p><p><strong>(a)</strong> The Health Service must not refuse the request unless:</p><p><strong>(i)</strong> the Health Service has consulted the Doctor;</p><p><strong>(ii)</strong> there are reasonable grounds to refuse the request; and</p><p><strong>(iii)</strong> the reasonable grounds are based on facts that are known, or reasonably foreseeable, at the time of refusing the request.</p><p><strong>(b)</strong> Without limiting subclause 16A.7 (a), reasonable grounds for refusing a request include the following:</p><p><strong>(i)</strong> it would require a significant adjustment to the Doctor’s hours of work in order for the Doctor to be employed as a Full-Time Doctor or Fractional Doctor;</p><p><strong>(ii)</strong> the Doctor’s position will cease to exist in the period of 12 months after giving the request;</p><p><strong>(iii)</strong> the hours of work which the Doctor is required to perform will be significantly reduced in the period of 12 months after giving the request;</p><p><strong>(iv)</strong> there will be a significant change in either or both of the following in the period of 12 months after giving the request:</p><p>A. the days on which the Doctor’s hours of work are required to be performed;</p><p>B. the times at which the Doctor’s hours of work are required to be performed;</p><p>which cannot be accommodated within the days or times the Doctor is available to work during that period;</p><p><strong>(v)</strong> granting the request would not comply with a recruitment or selection process required by or under a law of the Commonwealth or a State or a Territory</p><p><strong>(c)</strong> If the Health Service refuses the request, the written response under subclause 16.6 must include details of the reasons for the refusal.</p><p><strong>16A.8</strong> Grants of requests</p><p><strong>(a)</strong> If the Health Service grants the request, the Health Service must, within 21 days after the day the request is given to the Health Service, give written notice to the Doctor of the following:</p><p><strong>(i)</strong> whether the Doctor is converting to Full-Time employment or Fractional employment;</p><p><strong>(ii)</strong> the Doctor’s pattern of hours or shifts after the conversion takes effect;</p><p><strong>(iii)</strong> the day the Doctor’s conversion to full-time or fractional employment takes effect.</p><p><strong>(b)</strong> However, the Health Service must discuss with the Doctor the matters the Health Service intends to specify for the purposes of subclause 16A.8 (a)(i) -</p><p><strong>(iii)</strong> before giving the notice.</p><p><strong>(c)</strong> The day specified for the purposes of subclause 16A.8 (a)(iii) must be the first day of the Doctor’s first full pay period that starts after the day the notice is given, unless the Doctor and Health Service agree to another day.</p><p><strong>(d)</strong> To avoid doubt, the notice may be included in the written response under subclause 16A.6 .</p><p><strong>16A.9</strong> Effect of conversion</p><p><strong>(a)</strong> A Doctor is taken, on and after the day specified in a notice for the purposes of subclauses 16A.4(a)(iii) and 16A.8 (a)(iii) to be a Full-Time Doctor or a Fractional Doctor of the Health Service.</p><p><strong>(b)</strong> Any loading afforded under subclause 16.4 will cease, and, subject to subclause 16A.6 , any benefits relating to permanent employment will commence on the day specified in a notice for the purposes of subclauses 16A.4(a)(iii) and 16A.8 (a)(iii).</p>',88)])])}const f=t(n,[["render",i]]);export{g as __pageData,f as default};
